  render: () => <StoryFrame>
      <section className="paperclip-story__frame p-6">
        <div className="paperclip-story__label">Thread interactions</div>
        <div className="mt-2 max-w-3xl text-sm leading-6 text-muted-foreground">
          This review surface pressure-tests the thread interaction kinds directly inside the issue
          chat surface. The card language leans closer to
          annotated review sheets than generic admin widgets so the objects feel like first-class work
          artifacts in the thread.
        </div>
      </section>

      <Section eyebrow="Suggested Tasks" title="Pending, accepted, and rejected task-tree cards">
        <div className="grid gap-6 xl:grid-cols-3">
          <ScenarioCard title="Pending" description="The draft tree stays editable and non-persistent until someone accepts or rejects it.">
            <InteractiveSuggestedTasksCard />
          </ScenarioCard>
          <ScenarioCard title="Accepted" description="Accepted state resolves to created issue links while keeping the original suggestion visible in-thread.">
            <IssueThreadInteractionCard interaction={acceptedSuggestedTasksInteraction} agentMap={storybookAgentMap} currentUserId={issueThreadInteractionFixtureMeta.currentUserId} userLabelMap={boardUserLabels} />
          </ScenarioCard>
          <ScenarioCard title="Rejected" description="The rejection reason remains attached to the artifact so future reviewers can see why the draft was declined.">
            <IssueThreadInteractionCard interaction={rejectedSuggestedTasksInteraction} agentMap={storybookAgentMap} currentUserId={issueThreadInteractionFixtureMeta.currentUserId} userLabelMap={boardUserLabels} />
          </ScenarioCard>
        </div>
      </Section>

      <Section eyebrow="Ask User Questions" title="Pending multi-question form and answered summary">
        <div className="grid gap-6 xl:grid-cols-2">
          <ScenarioCard title="Pending" description="Answers stay local across the whole form and only wake the assignee once after final submit.">
            <InteractiveAskUserQuestionsCard />
          </ScenarioCard>
          <ScenarioCard title="Answered" description="The answered state keeps the exact choices visible and adds a compact summary note for later review.">
            <IssueThreadInteractionCard interaction={answeredAskUserQuestionsInteraction} agentMap={storybookAgentMap} currentUserId={issueThreadInteractionFixtureMeta.currentUserId} userLabelMap={boardUserLabels} />
          </ScenarioCard>
        </div>
      </Section>

      <Section eyebrow="Request Confirmation" title="Plan approval and compact resolution states">
        <div className="grid gap-6 xl:grid-cols-2">
          <ScenarioCard title="Plan approval" description="The pending card links to the watched plan revision and requires a reason when declined.">
            <InteractiveRequestConfirmationCard />
          </ScenarioCard>
          <ScenarioCard title="Accepted" description="Accepted confirmations stay visible as resolved work artifacts.">
            <IssueThreadInteractionCard interaction={acceptedRequestConfirmationInteraction} agentMap={storybookAgentMap} currentUserId={issueThreadInteractionFixtureMeta.currentUserId} userLabelMap={boardUserLabels} />
          </ScenarioCard>
          <ScenarioCard title="Rejected" description="Rejected confirmations keep the board's decline reason attached.">
            <IssueThreadInteractionCard interaction={rejectedRequestConfirmationInteraction} agentMap={storybookAgentMap} currentUserId={issueThreadInteractionFixtureMeta.currentUserId} userLabelMap={boardUserLabels} />
          </ScenarioCard>
          <ScenarioCard title="Expired states" description="Comment and target-change expiry states are compact and disabled.">
            <div className="space-y-4">
              <IssueThreadInteractionCard interaction={commentExpiredRequestConfirmationInteraction} agentMap={storybookAgentMap} currentUserId={issueThreadInteractionFixtureMeta.currentUserId} userLabelMap={boardUserLabels} />
              <IssueThreadInteractionCard interaction={staleTargetRequestConfirmationInteraction} agentMap={storybookAgentMap} currentUserId={issueThreadInteractionFixtureMeta.currentUserId} userLabelMap={boardUserLabels} />
            </div>
          </ScenarioCard>
        </div>
      </Section>

      <Section eyebrow="Mixed Feed" title="Interaction cards in the real issue thread">
        <ScenarioCard title="IssueChatThread composition" description="Comments, timeline events, accepted task suggestions, a pending confirmation, a pending question form, and an active run share the same feed.">
          <div className="overflow-hidden rounded-[32px] border border-border/70 bg-[linear-gradient(135deg,rgba(14,165,233,0.08),transparent_28%),linear-gradient(180deg,rgba(245,158,11,0.08),transparent_42%),var(--background)] p-5 shadow-[0_30px_80px_rgba(15,23,42,0.10)]">
            <IssueChatThread comments={issueThreadInteractionComments} interactions={mixedIssueThreadInteractions} timelineEvents={issueThreadInteractionEvents} liveRuns={issueThreadInteractionLiveRuns} transcriptsByRunId={issueThreadInteractionTranscriptsByRunId} hasOutputForRun={runId => runId === "run-thread-live"} companyId={issueThreadInteractionFixtureMeta.companyId} projectId={issueThreadInteractionFixtureMeta.projectId} currentUserId={issueThreadInteractionFixtureMeta.currentUserId} userLabelMap={boardUserLabels} agentMap={storybookAgentMap} onAdd={async () => {}} showComposer={false} />
          </div>
        </ScenarioCard>
      </Section>
    </StoryFrame>,
  parameters: {
    docs: {
      description: {
        story: "Covers the prototype states called out in [PAP-1709](/PAP/issues/PAP-1709): suggested-task previews, collapsed descendants, rejection reasons, request confirmations, multi-question answers, and a mixed issue thread."
      }
    }
  }
